final:
module RefModule(
    input        clk,
    input        clr,
    input  [3:0] A,
    input  [3:0] B,
    input        sub,
    output [3:0] Y
);reg [3:0] final_sig;

    always @(posedge clk)
        if (clr) final_sig <= 4'b0;
        else if (sub) final_sig <= A - B;
        else final_sig <= A + B;

    assign Y = final_sig;

endmodule
